                completion(.failure(HTTPClientError.httpError(statusCode: httpResponse.statusCode)))
                return
            }
            
            guard let data = data else {
                completion(.failure(HTTPClientError.noData))
                return
            }
            
            let responseString = String(data: data, encoding: .utf8) ?? "Binary data"
            completion(.success(responseString))
        }
        
        task.resume()
    }
}

enum HTTPClientError: Error {
    case invalidResponse
    case httpError(statusCode: Int)
    case noData
    case certificateValidationFailed
}

class CertificatePinner {
    private let pinnedCertificates: [String: [Data]]
    
    init() {
        self.pinnedCertificates = [
            "api.example.com": CertificatePinner.loadCertificates(named: "api_example_com")
        ]
    }
    
    private static func loadCertificates(named name: String) -> [Data] {
        guard let certPath = Bundle.main.path(forResource: name, ofType: "cer"),
              let certData = try? Data(contentsOf: URL(fileURLWithPath: certPath)) else {
            return []
        }
        return [certData]
    }
    
    func validate(serverTrust: SecTrust, forHost host: String) -> Bool {
        guard let pinnedCerts = pinnedCertificates[host], !pinnedCerts.isEmpty else {
            return true
        }
        
        var secResult = SecTrustResultType.invalid
        let status = SecTrustEvaluate(serverTrust, &secResult)
        
        guard status == errSecSuccess else {
            return false
        }
        
        let serverCertCount = SecTrustGetCertificateCount(serverTrust)
        
        for i in 0..<serverCertCount {
            guard let serverCert = SecTrustGetCertificateAtIndex(serverTrust, i) else {
                continue
            }
            
            let serverCertData = SecCertificateCopyData(serverCert) as Data
            
            for pinnedCertData in pinnedCerts {
                if serverCertData == pinnedCertData {
                    return true
                }
            }
        }
        
        return false
    }
}

class SecureURLSessionDelegate: NSObject, URLSessionDelegate {
    private let certificatePinner: CertificatePinner
    
    init(certificatePinner: CertificatePinner) {
        self.certificatePinner = certificatePinner
        super.init()
    }
    
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        let host = challenge.protectionSpace.host
        
        if certificatePinner.validate(serverTrust: serverTrust, forHost: host) {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}